import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.ePeAWSvT.js";const c=JSON.parse('{"title":"Branding","description":"","frontmatter":{},"headers":[],"relativePath":"guide/branding.md","filePath":"guide/branding.md"}'),n={name:"guide/branding.md"};function s(i,t,l,d,h,g){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="branding" tabindex="-1">Branding <a class="header-anchor" href="#branding" aria-label="Permalink to &quot;Branding&quot;">​</a></h1><p>The Branding page customizes how the platform looks for your tenant — the page title, primary color, header logos, bot illustration, and favicon. All changes apply across the app the next time it loads.</p><p>Open <strong>Settings → Branding</strong>.</p><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h2><p>The <strong>General</strong> tab controls non-image settings.</p><ul><li><strong>Page title</strong> — The text shown in the browser tab. Leave blank to use the platform default (&quot;Team Central&quot;).</li><li><strong>Primary color</strong> — The accent color used throughout the app, including the mobile browser chrome tint. Pick a hex value or use the swatch. Leave blank to use the platform default.</li></ul><h2 id="logos" tabindex="-1">Logos <a class="header-anchor" href="#logos" aria-label="Permalink to &quot;Logos&quot;">​</a></h2><p>The <strong>Logos</strong> tab uploads the images used across the app. Each asset has a <strong>Default</strong> version (always used) and an optional <strong>Dark</strong> version (used when the viewer&#39;s OS is in dark mode). If a Dark version is blank, the Default is used in both modes.</p><h3 id="size-requirements" tabindex="-1">Size requirements <a class="header-anchor" href="#size-requirements" aria-label="Permalink to &quot;Size requirements&quot;">​</a></h3><p>All uploads accept <strong>SVG, PNG, or JPEG</strong> up to <strong>1 MB</strong>, with these per-asset rules:</p><table tabindex="0"><thead><tr><th>Asset</th><th>Formats</th><th>Max size</th><th>Dimensions</th><th>Aspect ratio</th><th>Used for</th></tr></thead><tbody><tr><td>Header logo</td><td>SVG, PNG, JPEG</td><td>1 MB</td><td>Recommended <strong>~200 × 60</strong></td><td>Any</td><td>Top-left header, login page</td></tr><tr><td>Bot illustration</td><td>SVG, PNG, JPEG</td><td>1 MB</td><td>Recommended <strong>256 × 256</strong></td><td><strong>Square</strong></td><td>AI assistant avatar</td></tr><tr><td>Favicon / app icon</td><td><strong>PNG or JPEG</strong></td><td>1 MB</td><td><strong>At least 256 × 256</strong></td><td><strong>Square</strong></td><td>Browser favicon, Apple touch icon, Windows Start tile</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Why these sizes?</p><ul><li>The favicon is reused as the Apple touch icon (180 × 180) and Windows tile (270 × 270), so the master needs to be at least 256 × 256 and square — the app rejects uploads that don&#39;t meet this.</li><li>The bot illustration renders inside a square frame; non-square uploads are rejected to avoid letterboxing.</li><li>The header logo has no strict ratio, but ~200 × 60 with a transparent background fits the header cleanly. SVG is preferred — it stays sharp at any zoom level.</li></ul></div><h3 id="header-logo" tabindex="-1">Header logo <a class="header-anchor" href="#header-logo" aria-label="Permalink to &quot;Header logo&quot;">​</a></h3><p>The main brand mark shown in the top-left of the app and on the login screen. Use <strong>SVG</strong> with a transparent background when possible so it works on any header color.</p><h3 id="bot-illustration" tabindex="-1">Bot illustration <a class="header-anchor" href="#bot-illustration" aria-label="Permalink to &quot;Bot illustration&quot;">​</a></h3><p>The avatar shown beside AI assistant messages. Must be square.</p><h3 id="favicon-app-icon" tabindex="-1">Favicon / app icon <a class="header-anchor" href="#favicon-app-icon" aria-label="Permalink to &quot;Favicon / app icon&quot;">​</a></h3><p>The icon used for the browser tab, mobile home-screen bookmark, and Windows Start tile. <strong>PNG or JPEG only</strong> — Apple touch and Windows tile metadata don&#39;t support SVG. Must be square and at least 256 × 256.</p><h3 id="dark-variants" tabindex="-1">Dark variants <a class="header-anchor" href="#dark-variants" aria-label="Permalink to &quot;Dark variants&quot;">​</a></h3><p>Optional <strong>Dark</strong> versions of the header logo and bot illustration are used when the viewer&#39;s OS is in dark mode. Leave them blank to reuse the default upload. The favicon doesn&#39;t have a dark variant — operating systems handle icon contrast themselves.</p><h2 id="saving-and-resetting" tabindex="-1">Saving and resetting <a class="header-anchor" href="#saving-and-resetting" aria-label="Permalink to &quot;Saving and resetting&quot;">​</a></h2><p>The <strong>Save</strong> button enables once you&#39;ve made changes. <strong>Reset</strong> discards unsaved edits and restores the last saved configuration. Clearing an individual upload restores that asset to the platform default.</p><h2 id="key-features" tabindex="-1">Key features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key features&quot;">​</a></h2><ul><li><strong>Page title and primary color</strong> — Customize basic chrome</li><li><strong>Five logo slots</strong> — Light + dark header logo, light + dark bot illustration, and favicon</li><li><strong>Per-asset validation</strong> — Square / minimum-size rules enforced at upload</li><li><strong>Dark mode fallback</strong> — Dark uploads are optional; the platform falls back to the default upload when omitted</li><li><strong>Live across tabs</strong> — Saved branding broadcasts to other open tabs and applies on next page render</li></ul>',24)])])}const p=e(n,[["render",s]]);export{c as __pageData,p as default};
